#!/usr/bin/env node

import { constants as fsConstants } from 'node:fs';
import { accessSync } from 'node:fs';
import { spawnSync } from 'node:child_process';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';
import { createRequire } from 'node:module';

const here = dirname(fileURLToPath(import.meta.url));
const require = createRequire(import.meta.url);
const tsxPackagePath = require.resolve('tsx/package.json');
const tsxCliPath = resolve(dirname(tsxPackagePath), 'dist/cli.mjs');

function canExecute(path) {
  try {
    accessSync(path, fsConstants.X_OK);
    return true;
  } catch {
    return false;
  }
}

function runNativeIfPresent(candidates) {
  for (const binPath of candidates) {
    if (!canExecute(binPath)) continue;
    const native = spawnSync(binPath, process.argv.slice(2), { stdio: 'inherit' });
    if (native.error) {
      throw native.error;
    }
    process.exit(native.status ?? 1);
  }
}

/**
 * Non-TS CLI entrypoint shim.
 * Priority:
 * 1) Native binary (Rust/C) if explicitly requested.
 * 2) TS source via tsx fallback.
 */
async function main() {
  if (process.argv[2] === 'monster-mesh') {
    const { runMonsterMeshFromWrapper } = await import(
      '../rtlsdr-mock-sim/wrapper-mesh-delegation.mjs',
    );
    await runMonsterMeshFromWrapper(here, process.argv.slice(2));
    return;
  }

  const nativeOverride = process.env.GNOSIS_RTLSDR_MOCK_SIM_BIN
    ? resolve(process.env.GNOSIS_RTLSDR_MOCK_SIM_BIN)
    : null;
  if (nativeOverride !== null) {
    runNativeIfPresent([nativeOverride]);
  }
  if (process.env.GNOSIS_RTLSDR_MOCK_SIM_USE_NATIVE === '1') {
    runNativeIfPresent([
      resolve(here, '../target/release/rtlsdr-mock-sim'),
      resolve(here, '../bin-native/rtlsdr-mock-sim'),
    ]);
  }

  const sourceCliPath = resolve(here, '../rtlsdr-mock-sim/run.mts');
  const result = spawnSync(
    process.execPath,
    [tsxCliPath, sourceCliPath, ...process.argv.slice(2)],
    { stdio: 'inherit' },
  );
  if (result.error) {
    throw result.error;
  }
  process.exit(result.status ?? 1);
}

await main();
